using UnityEngine;
using UnityEngine.Events;
using UnityEngine.EventSystems;
using UnityEngine.InputSystem;
using UnityEngine.UI;

/// <summary>
/// Botão que só confirma a acção depois de mantido premido durante
/// <see cref="holdDuration"/> segundos — usado por "Regressar ao Coração de
/// Gaia" (Menu de Pausa: Opções, Tarefa #12): "Confirmar precisaria de segurar
/// o botão durante um segundo", precisamente para não ser escolhido por acidente.
///
/// Funciona por rato/toque (IPointerDownHandler/IPointerUpHandler) E por
/// comando/teclado: enquanto este botão está seleccionado
/// (EventSystem.current.currentSelectedGameObject == este GameObject), mantém
/// "Sul"/Enter/Espaço premido para acumular o progresso.
///
/// <see cref="fillImage"/> (Image do tipo "Filled") mostra o progresso
/// (0 → 1). Soltar antes do tempo reinicia o progresso sem confirmar.
/// </summary>
public class HoldToConfirmButton : MonoBehaviour, IPointerDownHandler, IPointerUpHandler, IPointerExitHandler
{
    [Tooltip("Tempo (segundos) que o botão precisa de ser mantido premido para confirmar (GDD: \"durante um segundo\").")]
    [SerializeField] private float holdDuration = 1f;

    [Tooltip("Image do tipo \"Filled\" que mostra o progresso do hold (0 a 1). Opcional.")]
    [SerializeField] private Image fillImage;

    /// <summary>Disparado quando o hold completa "holdDuration" segundos sem ser solto.</summary>
    public UnityEvent OnConfirmed;

    private float holdTime;
    private bool pointerHeld;
    private bool confirmed;

    private void OnEnable()
    {
        ResetProgress();
    }

    private void OnDisable()
    {
        ResetProgress();
    }

    private void Update()
    {
        bool held = pointerHeld || IsSubmitHeldWhileSelected();

        if (!held)
        {
            if (holdTime > 0f) ResetProgress();
            return;
        }

        if (confirmed) return;

        holdTime += Time.unscaledDeltaTime;
        UpdateFill();

        if (holdTime >= holdDuration)
        {
            confirmed = true;
            OnConfirmed?.Invoke();
        }
    }

    private bool IsSubmitHeldWhileSelected()
    {
        if (EventSystem.current == null) return false;
        if (EventSystem.current.currentSelectedGameObject != gameObject) return false;

        if (Keyboard.current != null && (Keyboard.current.enterKey.isPressed || Keyboard.current.spaceKey.isPressed)) return true;
        if (Gamepad.current != null && Gamepad.current.buttonSouth.isPressed) return true;

        return false;
    }

    private void UpdateFill()
    {
        if (fillImage != null) fillImage.fillAmount = Mathf.Clamp01(holdTime / Mathf.Max(0.01f, holdDuration));
    }

    private void ResetProgress()
    {
        holdTime = 0f;
        confirmed = false;
        pointerHeld = false;
        UpdateFill();
    }

    public void OnPointerDown(PointerEventData eventData) => pointerHeld = true;

    public void OnPointerUp(PointerEventData eventData) => pointerHeld = false;

    public void OnPointerExit(PointerEventData eventData) => pointerHeld = false;
}
